import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
} from '@angular/core';
import { MatExpansionModule } from '@angular/material/expansion';

export interface MfAccordionPanel {
  title: string;
  description?: string;
  content: string;
  expanded?: boolean;
  disabled?: boolean;
}

/**
 * Accordion de la librería mf-components.
 * Envuelve Angular Material `mat-accordion` / `mat-expansion-panel` y expone
 * una API uniforme con look and feel de marca.
 */
@Component({
  selector: 'mf-accordion',
  imports: [MatExpansionModule],
  template: `
    <mat-accordion [multi]="multi()" [class]="hostClasses()">
      @for (panel of panels(); track panel.title) {
        <mat-expansion-panel
          [expanded]="panel.expanded ?? false"
          [disabled]="panel.disabled ?? false"
        >
          <mat-expansion-panel-header>
            <mat-panel-title>{{ panel.title }}</mat-panel-title>
            @if (panel.description) {
              <mat-panel-description>{{ panel.description }}</mat-panel-description>
            }
          </mat-expansion-panel-header>
          <p>{{ panel.content }}</p>
        </mat-expansion-panel>
      }
    </mat-accordion>
  `,
  styleUrl: './mf-accordion.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfAccordionComponent {
  /** Paneles del accordion */
  readonly panels = input.required<MfAccordionPanel[]>();
  /** Permite múltiples paneles abiertos */
  readonly multi = input(false);

  readonly hostClasses = computed(() => 'mf-accordion');
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  input,
  output,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatAutocompleteModule } from '@angular/material/autocomplete';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';

export interface MfAutocompleteOption {
  value: string | number;
  label: string;
  disabled?: boolean;
}

export type MfAutocompleteSize = 'sm' | 'md' | 'lg';

/**
 * Autocompletar de la librería mf-components.
 * Envuelve Angular Material `mat-autocomplete` y expone una API uniforme
 * con look and feel de marca.
 *
 * El panel desplegable se estiliza con la clase global `mf-autocomplete-panel`.
 * Puedes añadir clases adicionales con `panelClass`.
 */
@Component({
  selector: 'mf-autocomplete',
  imports: [
    FormsModule,
    MatAutocompleteModule,
    MatFormFieldModule,
    MatIconModule,
    MatInputModule,
  ],
  template: `
    <mat-form-field [appearance]="'outline'" [class]="hostClasses()">
      @if (label()) {
        <mat-label>{{ label() }}</mat-label>
      }
      @if (leadingIcon()) {
        <mat-icon matPrefix aria-hidden="true">{{ leadingIcon() }}</mat-icon>
      }
      <input
        matInput
        [placeholder]="placeholder()"
        [disabled]="disabled()"
        [matAutocomplete]="auto"
        [(ngModel)]="inputValue"
        (ngModelChange)="onInputChange($event)"
        (blur)="mfBlur.emit()"
      />
      @if (trailingIcon()) {
        <mat-icon matSuffix aria-hidden="true">{{ trailingIcon() }}</mat-icon>
      }
      @if (hint()) {
        <mat-hint>{{ hint() }}</mat-hint>
      }
      @if (error()) {
        <mat-error>{{ error() }}</mat-error>
      }
      <mat-autocomplete
        #auto
        [panelWidth]="panelWidth()"
        [class]="autocompletePanelClasses()"
        (optionSelected)="onOptionSelected($event)"
      >
        @for (option of filteredOptions(); track option.value) {
          <mat-option [value]="option.label" [disabled]="option.disabled ?? false">
            {{ option.label }}
          </mat-option>
        }
      </mat-autocomplete>
    </mat-form-field>
  `,
  styleUrl: './mf-autocomplete.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfAutocompleteComponent {
  /** Lista completa de opciones */
  readonly options = input.required<MfAutocompleteOption[]>();
  /** Etiqueta flotante del campo */
  readonly label = input<string | undefined>(undefined);
  /** Placeholder del input */
  readonly placeholder = input('');
  /** Valor actual (texto en el campo) */
  readonly value = input('');
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Tamaño del campo */
  readonly size = input<MfAutocompleteSize>('md');
  /** Ancho completo */
  readonly fullWidth = input(false);
  /** Texto de ayuda debajo del campo */
  readonly hint = input<string | undefined>(undefined);
  /** Mensaje de error */
  readonly error = input<string | undefined>(undefined);
  /** Icono al inicio del campo */
  readonly leadingIcon = input<string | undefined>(undefined);
  /** Icono al final del campo */
  readonly trailingIcon = input<string | undefined>(undefined);
  /**
   * Ancho del panel del autocomplete.
   * Por defecto `''`: el panel toma el mismo ancho que el campo.
   * Acepta cualquier valor CSS válido ('300px', '80vw', etc.) para sobreescribirlo.
   */
  readonly panelWidth = input<string | number>('');
  /**
   * Clases extra que se añaden al panel del autocomplete (overlay).
   * La clase `mf-autocomplete-panel` siempre está presente.
   */
  readonly panelClass = input<string | string[]>('');

  /** Emite el texto escrito en el campo */
  readonly mfInput = output<string>();
  /** Emite el valor de la opción seleccionada */
  readonly mfOptionSelected = output<MfAutocompleteOption>();
  readonly mfBlur = output<void>();

  inputValue = '';

  readonly hostClasses = computed(() => {
    const classes = ['mf-autocomplete', `mf-autocomplete--${this.size()}`];
    if (this.fullWidth()) classes.push('mf-autocomplete--full');
    if (this.error()) classes.push('mf-autocomplete--error');
    return classes.join(' ');
  });

  readonly autocompletePanelClasses = computed(() => {
    const base = ['mf-autocomplete-panel'];
    const extra = this.panelClass();
    if (Array.isArray(extra)) {
      base.push(...extra.filter(Boolean));
    } else if (extra) {
      base.push(extra);
    }
    return base.join(' ');
  });

  readonly filteredOptions = computed(() => {
    const query = this.inputValue.toLowerCase().trim();
    if (!query) return this.options();
    return this.options().filter((o) =>
      o.label.toLowerCase().includes(query)
    );
  });

  constructor() {
    effect(() => {
      this.inputValue = this.value();
    });
  }

  onInputChange(value: string): void {
    this.mfInput.emit(value);
  }

  onOptionSelected(event: { option: { value: string } }): void {
    const label = event.option.value;
    const match = this.options().find((o) => o.label === label);
    if (match) {
      this.mfOptionSelected.emit(match);
    }
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatIconModule } from '@angular/material/icon';

export interface MfBreadcrumbItem {
  label: string;
  href?: string;
  icon?: string;
}

/**
 * Breadcrumb de la librería mf-components.
 * Componente de navegación jerárquica para indicar la ubicación
 * del usuario en la aplicación.
 */
@Component({
  selector: 'mf-breadcrumb',
  imports: [MatIconModule],
  template: `
    <nav [attr.aria-label]="ariaLabel()" [class]="hostClasses()">
      <ol class="mf-breadcrumb__list">
        @for (item of items(); track item.label; let last = $last) {
          <li class="mf-breadcrumb__item">
            @if (!last && item.href) {
              <a
                class="mf-breadcrumb__link"
                [href]="item.href"
                (click)="onItemClick($event, item)"
              >
                @if (item.icon) {
                  <mat-icon class="mf-breadcrumb__icon" aria-hidden="true">{{ item.icon }}</mat-icon>
                }
                {{ item.label }}
              </a>
            } @else {
              <span class="mf-breadcrumb__current" [attr.aria-current]="last ? 'page' : null">
                @if (item.icon) {
                  <mat-icon class="mf-breadcrumb__icon" aria-hidden="true">{{ item.icon }}</mat-icon>
                }
                {{ item.label }}
              </span>
            }
            @if (!last) {
              <mat-icon class="mf-breadcrumb__separator" aria-hidden="true">{{ separator() }}</mat-icon>
            }
          </li>
        }
      </ol>
    </nav>
  `,
  styleUrl: './mf-breadcrumb.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfBreadcrumbComponent {
  /** Items del breadcrumb */
  readonly items = input.required<MfBreadcrumbItem[]>();
  /** Icono separador */
  readonly separator = input<string>('chevron_right');
  /** Label de accesibilidad */
  readonly ariaLabel = input<string>('Breadcrumb');

  readonly mfItemClick = output<MfBreadcrumbItem>();

  readonly hostClasses = computed(() => 'mf-breadcrumb');

  onItemClick(event: Event, item: MfBreadcrumbItem): void {
    event.preventDefault();
    this.mfItemClick.emit(item);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  input,
} from '@angular/core';
import { MatGridListModule } from '@angular/material/grid-list';

export interface MfGridTile {
  /** Título de la tile */
  title?: string;
  /** Subtítulo de la tile */
  subtitle?: string;
  /** Número de columnas que ocupa */
  colspan?: number;
  /** Número de filas que ocupa */
  rowspan?: number;
  /** Color de fondo */
  background?: string;
}

/**
 * Lista en cuadrícula de la librería mf-components.
 * Envuelve Angular Material `mat-grid-list` y expone una API uniforme
 * con look and feel de marca. Soporta tiles estáticas y content projection.
 */
@Component({
  selector: 'mf-grid-list',
  imports: [MatGridListModule],
  template: `
    <mat-grid-list
      class="mf-grid-list"
      [cols]="cols()"
      [rowHeight]="rowHeight()"
      [gutterSize]="gutterSize()"
    >
      @for (tile of tiles(); track $index) {
        <mat-grid-tile
          class="mf-grid-list__tile"
          [colspan]="tile.colspan ?? 1"
          [rowspan]="tile.rowspan ?? 1"
          [style.background]="tile.background || null"
        >
          <mat-grid-tile-header>
            @if (tile.title) {
              <span class="mf-grid-list__tile-title">{{ tile.title }}</span>
            }
            @if (tile.subtitle) {
              <span class="mf-grid-list__tile-subtitle">{{ tile.subtitle }}</span>
            }
          </mat-grid-tile-header>
        </mat-grid-tile>
      }
      <ng-content />
    </mat-grid-list>
  `,
  styleUrl: './mf-grid-list.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfGridListComponent {
  /** Número de columnas */
  readonly cols = input(2);
  /** Altura de cada fila */
  readonly rowHeight = input<string | number>('1:1');
  /** Espacio entre tiles */
  readonly gutterSize = input('8px');
  /** Tiles a renderizar */
  readonly tiles = input<MfGridTile[]>([]);
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatMenuModule } from '@angular/material/menu';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';

export interface MfMenuItem {
  label: string;
  icon?: string;
  disabled?: boolean;
  value: string;
}

/**
 * Menu de la librería mf-components.
 * Envuelve Angular Material `mat-menu` y expone una API uniforme
 * con look and feel de marca.
 */
@Component({
  selector: 'mf-menu',
  imports: [MatMenuModule, MatButtonModule, MatIconModule],
  template: `
    <button
      mat-icon-button
      [matMenuTriggerFor]="menu"
      [class]="triggerClasses()"
      [attr.aria-label]="triggerLabel()"
    >
      <mat-icon>{{ triggerIcon() }}</mat-icon>
    </button>
    <mat-menu #menu="matMenu" [class]="hostClasses()">
      @for (item of items(); track item.value) {
        <button
          mat-menu-item
          [disabled]="item.disabled ?? false"
          (click)="mfItemClick.emit(item.value)"
        >
          @if (item.icon) {
            <mat-icon aria-hidden="true">{{ item.icon }}</mat-icon>
          }
          <span>{{ item.label }}</span>
        </button>
      }
    </mat-menu>
  `,
  styleUrl: './mf-menu.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfMenuComponent {
  /** Items del menú */
  readonly items = input.required<MfMenuItem[]>();
  /** Icono del trigger */
  readonly triggerIcon = input<string>('more_vert');
  /** Label accesible del trigger */
  readonly triggerLabel = input<string>('Abrir menú');

  readonly mfItemClick = output<string>();

  readonly hostClasses = computed(() => 'mf-menu');
  readonly triggerClasses = computed(() => 'mf-menu__trigger');
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  input,
  output,
  signal,
} from '@angular/core';
import { MatRadioModule } from '@angular/material/radio';
import { FormsModule } from '@angular/forms';

export interface MfRadioOption {
  /** Valor de la opción */
  value: string;
  /** Texto visible */
  label: string;
  /** Deshabilitada individualmente */
  disabled?: boolean;
}

export type MfRadioDirection = 'horizontal' | 'vertical';

/**
 * Grupo de radio buttons de la librería mf-components.
 * Envuelve Angular Material `mat-radio-group` + `mat-radio-button`
 * y expone una API uniforme con look and feel de marca.
 */
@Component({
  selector: 'mf-radio-button',
  imports: [MatRadioModule, FormsModule],
  template: `
    <mat-radio-group
      [class]="hostClasses()"
      [disabled]="disabled()"
      [ngModel]="currentValue()"
      (change)="onChange($event)"
      [attr.aria-label]="ariaLabel() || null"
    >
      @for (option of options(); track option.value) {
        <mat-radio-button
          class="mf-radio__option"
          [value]="option.value"
          [disabled]="option.disabled ?? false"
        >
          {{ option.label }}
        </mat-radio-button>
      }
    </mat-radio-group>
  `,
  styleUrl: './mf-radio-button.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfRadioButtonComponent {
  /** Opciones del grupo */
  readonly options = input.required<MfRadioOption[]>();
  /** Valor seleccionado */
  readonly value = input<string | undefined>(undefined);
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Dirección del grupo */
  readonly direction = input<MfRadioDirection>('vertical');
  /** Etiqueta accesible para el grupo */
  readonly ariaLabel = input<string | undefined>(undefined);

  readonly mfChange = output<string>();

  protected readonly currentValue = signal<string | undefined>(undefined);

  constructor() {
    effect(() => {
      this.currentValue.set(this.value());
    });
  }

  readonly hostClasses = computed(() => {
    return `mf-radio mf-radio--${this.direction()}`;
  });

  onChange(event: { value: string }): void {
    this.currentValue.set(event.value);
    this.mfChange.emit(event.value);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatSelectModule } from '@angular/material/select';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';

export interface MfSelectOption {
  value: string | number;
  label: string;
  disabled?: boolean;
}

export type MfSelectSize = 'sm' | 'md' | 'lg';

/**
 * Select de la librería mf-components.
 * Envuelve Angular Material `mat-select` y expone una API uniforme
 * con look and feel de marca.
 *
 * El dropdown se estiliza mediante la clase global `mf-select-panel` que se
 * inserta en el overlay. Puedes añadir clases adicionales con `panelClass`.
 */
@Component({
  selector: 'mf-select',
  imports: [MatSelectModule, MatFormFieldModule, MatIconModule],
  template: `
    <mat-form-field [appearance]="'outline'" [class]="hostClasses()">
      @if (label()) {
        <mat-label>{{ label() }}</mat-label>
      }
      @if (leadingIcon()) {
        <mat-icon matPrefix aria-hidden="true">{{ leadingIcon() }}</mat-icon>
      }
      <mat-select
        [value]="value()"
        [disabled]="disabled()"
        [multiple]="multiple()"
        [placeholder]="placeholder()"
        [panelClass]="panelClasses()"
        (selectionChange)="onSelectionChange($event)"
      >
        @for (option of options(); track option.value) {
          <mat-option [value]="option.value" [disabled]="option.disabled ?? false">
            {{ option.label }}
          </mat-option>
        }
      </mat-select>
      @if (trailingIcon()) {
        <mat-icon matSuffix aria-hidden="true">{{ trailingIcon() }}</mat-icon>
      }
      @if (hint()) {
        <mat-hint>{{ hint() }}</mat-hint>
      }
      @if (error()) {
        <mat-error>{{ error() }}</mat-error>
      }
    </mat-form-field>
  `,
  styleUrl: './mf-select.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfSelectComponent {
  /** Opciones del select */
  readonly options = input.required<MfSelectOption[]>();
  /** Etiqueta flotante */
  readonly label = input<string | undefined>(undefined);
  /** Placeholder */
  readonly placeholder = input<string>('');
  /** Valor actual */
  readonly value = input<string | number | (string | number)[] | undefined>(undefined);
  /** Selección múltiple */
  readonly multiple = input(false);
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Texto de ayuda */
  readonly hint = input<string | undefined>(undefined);
  /** Mensaje de error */
  readonly error = input<string | undefined>(undefined);
  /** Tamaño del campo */
  readonly size = input<MfSelectSize>('md');
  /** Ancho completo */
  readonly fullWidth = input(false);
  /** Icono al inicio del campo */
  readonly leadingIcon = input<string | undefined>(undefined);
  /** Icono al final del campo */
  readonly trailingIcon = input<string | undefined>(undefined);
  /**
   * Clases extra que se añaden al panel del dropdown (overlay).
   * La clase `mf-select-panel` siempre está presente para los estilos base.
   */
  readonly panelClass = input<string | string[]>('');

  readonly mfSelectionChange = output<string | number | (string | number)[]>();

  readonly hostClasses = computed(() => {
    const classes = ['mf-select', `mf-select--${this.size()}`];
    if (this.fullWidth()) classes.push('mf-select--full');
    if (this.error()) classes.push('mf-select--error');
    return classes.join(' ');
  });

  readonly panelClasses = computed(() => {
    const base = ['mf-select-panel'];
    const extra = this.panelClass();
    if (Array.isArray(extra)) {
      base.push(...extra.filter(Boolean));
    } else if (extra) {
      base.push(extra);
    }
    return base;
  });

  onSelectionChange(event: { value: string | number | (string | number)[] }): void {
    this.mfSelectionChange.emit(event.value);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatSidenavModule } from '@angular/material/sidenav';
import { MatIconModule } from '@angular/material/icon';

export type MfSidenavMode = 'over' | 'push' | 'side';
export type MfSidenavPosition = 'start' | 'end';

export interface MfSidenavNavItem {
  /** Nombre del icono Material (e.g. 'home', 'dashboard') */
  icon: string;
  /** Texto de la etiqueta */
  label: string;
  /** Identificador único del ítem */
  id: string;
  /** Ítem activo/seleccionado */
  active?: boolean;
  /** Deshabilitar el ítem */
  disabled?: boolean;
  /** Número de badge (0 oculta el badge) */
  badge?: number;
}

/**
 * Panel lateral de la librería mf-components.
 * Envuelve Angular Material `mat-sidenav-container` y expone una API uniforme
 * con look and feel de marca.
 *
 * Dos formas de uso:
 * 1. **Navitems declarativos** — Proporciona `navItems`, `headerTitle` e icono.
 * 2. **Content projection** — Proyecta `[mfSidenavContent]` para control total.
 *
 * El contenido principal se proyecta sin atributo.
 */
@Component({
  selector: 'mf-sidenav',
  imports: [MatSidenavModule, MatIconModule],
  template: `
    <mat-sidenav-container [class]="containerClasses()" [hasBackdrop]="hasBackdrop()">
      <mat-sidenav
        [class]="sidenavClasses()"
        [mode]="mode()"
        [position]="position()"
        [opened]="opened()"
        [style.width]="sidenavWidth()"
        (openedChange)="mfOpenedChange.emit($event)"
      >
        @if (navItems().length > 0) {
          <div class="mf-sidenav__nav">
            @if (headerTitle()) {
              <div class="mf-sidenav__header">
                @if (headerIcon()) {
                  <mat-icon class="mf-sidenav__header-icon" aria-hidden="true">{{ headerIcon() }}</mat-icon>
                }
                <span class="mf-sidenav__header-title">{{ headerTitle() }}</span>
              </div>
            }
            <nav class="mf-sidenav__menu" [attr.aria-label]="navAriaLabel()">
              @for (item of navItems(); track item.id) {
                <button
                  type="button"
                  class="mf-sidenav__item"
                  [class.mf-sidenav__item--active]="item.active"
                  [class.mf-sidenav__item--disabled]="item.disabled"
                  [disabled]="item.disabled ?? false"
                  [attr.aria-current]="item.active ? 'page' : null"
                  (click)="!item.disabled && mfNavItemClick.emit(item)"
                >
                  <mat-icon class="mf-sidenav__item-icon" aria-hidden="true">{{ item.icon }}</mat-icon>
                  <span class="mf-sidenav__item-label">{{ item.label }}</span>
                  @if (item.badge && item.badge > 0) {
                    <span class="mf-sidenav__item-badge" aria-label="{{ item.badge }} notificaciones">
                      {{ item.badge > 99 ? '99+' : item.badge }}
                    </span>
                  }
                </button>
              }
            </nav>
          </div>
        } @else {
          <ng-content select="[mfSidenavContent]" />
        }
      </mat-sidenav>
      <mat-sidenav-content class="mf-sidenav__main">
        <ng-content />
      </mat-sidenav-content>
    </mat-sidenav-container>
  `,
  styleUrl: './mf-sidenav.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfSidenavComponent {
  /** Abierto o cerrado */
  readonly opened = input(false);
  /** Modo de apertura */
  readonly mode = input<MfSidenavMode>('side');
  /** Posición del panel */
  readonly position = input<MfSidenavPosition>('start');
  /** Muestra backdrop al abrir */
  readonly hasBackdrop = input<boolean | null>(null);
  /** Ancho del panel lateral */
  readonly sidenavWidth = input('260px');
  /** Ítems de navegación declarativos */
  readonly navItems = input<MfSidenavNavItem[]>([]);
  /** Título de la cabecera del sidenav */
  readonly headerTitle = input<string | undefined>(undefined);
  /** Icono Material de la cabecera */
  readonly headerIcon = input<string | undefined>(undefined);
  /** Aria-label del elemento nav */
  readonly navAriaLabel = input('Navegación principal');

  readonly mfOpenedChange = output<boolean>();
  /** Emite el ítem de navegación pulsado */
  readonly mfNavItemClick = output<MfSidenavNavItem>();

  readonly containerClasses = computed(() => 'mf-sidenav-container');

  readonly sidenavClasses = computed(() => {
    return `mf-sidenav mf-sidenav--${this.mode()}`;
  });
}

import { inject, Injectable } from '@angular/core';
import { MatSnackBar, MatSnackBarConfig, MatSnackBarRef, TextOnlySnackBar } from '@angular/material/snack-bar';

export type MfSnackbarType = 'info' | 'success' | 'warning' | 'error';

export interface MfSnackbarConfig {
  message: string;
  action?: string;
  type?: MfSnackbarType;
  duration?: number;
  horizontalPosition?: 'start' | 'center' | 'end';
  verticalPosition?: 'top' | 'bottom';
}

/**
 * Servicio de Snackbar de la librería mf-components.
 * Envuelve Angular Material `MatSnackBar` y expone una API uniforme
