import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';

/**
 * Slide Toggle de la librería mf-components.
 * Envuelve Angular Material `mat-slide-toggle` y expone una API uniforme
 * con look and feel de marca.
 */
@Component({
  selector: 'mf-slide-toggle',
  imports: [MatSlideToggleModule],
  template: `
    <mat-slide-toggle
      [checked]="checked()"
      [disabled]="disabled()"
      [class]="hostClasses()"
      (change)="onChange($event)"
    >
      {{ label() }}
    </mat-slide-toggle>
  `,
  styleUrl: './mf-slide-toggle.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfSlideToggleComponent {
  /** Texto descriptivo */
  readonly label = input<string>('');
  /** Estado activado */
  readonly checked = input(false);
  /** Deshabilitado */
  readonly disabled = input(false);

  readonly mfChange = output<boolean>();

  readonly hostClasses = computed(() => {
    const classes = ['mf-slide-toggle'];
    if (this.disabled()) classes.push('mf-slide-toggle--disabled');
    return classes.join(' ');
  });

  onChange(event: { checked: boolean }): void {
    this.mfChange.emit(event.checked);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatTableModule } from '@angular/material/table';
import { MatSortModule, Sort } from '@angular/material/sort';

export interface MfTableColumn {
  key: string;
  header: string;
  sortable?: boolean;
}

export type MfTableVariant = 'default' | 'striped' | 'bordered';

/**
 * Table de la librería mf-components.
 * Envuelve Angular Material `mat-table` y expone una API uniforme
 * con look and feel de marca. Ideal para dashboards y paneles de datos.
 */
@Component({
  selector: 'mf-table',
  imports: [MatTableModule, MatSortModule],
  template: `
    <div class="mf-table__wrapper" [class]="hostClasses()">
      <table
        mat-table
        [dataSource]="data()"
        matSort
        (matSortChange)="mfSortChange.emit($event)"
      >
        @for (col of columns(); track col.key) {
          <ng-container [matColumnDef]="col.key">
            @if (col.sortable) {
              <th mat-header-cell *matHeaderCellDef mat-sort-header>{{ col.header }}</th>
            } @else {
              <th mat-header-cell *matHeaderCellDef>{{ col.header }}</th>
            }
            <td mat-cell *matCellDef="let row">{{ row[col.key] }}</td>
          </ng-container>
        }

        <tr mat-header-row *matHeaderRowDef="displayedColumns()"></tr>
        <tr mat-row *matRowDef="let row; columns: displayedColumns()" (click)="mfRowClick.emit(row)"></tr>
      </table>
    </div>
  `,
  styleUrl: './mf-table.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfTableComponent {
  /** Columnas de la tabla */
  readonly columns = input.required<MfTableColumn[]>();
  /** Datos de la tabla */
  readonly data = input.required<Record<string, unknown>[]>();
  /** Variante visual */
  readonly variant = input<MfTableVariant>('default');

  readonly mfSortChange = output<Sort>();
  readonly mfRowClick = output<Record<string, unknown>>();

  readonly displayedColumns = computed(() => this.columns().map(c => c.key));

  readonly hostClasses = computed(() => {
    return ['mf-table', `mf-table--${this.variant()}`].join(' ');
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatTabsModule } from '@angular/material/tabs';
import { MatIconModule } from '@angular/material/icon';

export interface MfTab {
  label: string;
  icon?: string;
  disabled?: boolean;
}

export type MfTabsVariant = 'default' | 'stretched';

/**
 * Tabs de la librería mf-components.
 * Envuelve Angular Material `mat-tab-group` y expone una API uniforme
 * con look and feel de marca.
 */
@Component({
  selector: 'mf-tabs',
  imports: [MatTabsModule, MatIconModule],
  template: `
    <mat-tab-group
      [selectedIndex]="selectedIndex()"
      [class]="hostClasses()"
      [mat-stretch-tabs]="variant() === 'stretched'"
      (selectedIndexChange)="mfSelectedIndexChange.emit($event)"
    >
      @for (tab of tabs(); track tab.label) {
        <mat-tab [disabled]="tab.disabled ?? false">
          <ng-template mat-tab-label>
            @if (tab.icon) {
              <mat-icon class="mf-tabs__icon" aria-hidden="true">{{ tab.icon }}</mat-icon>
            }
            {{ tab.label }}
          </ng-template>
        </mat-tab>
      }
    </mat-tab-group>
  `,
  styleUrl: './mf-tabs.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfTabsComponent {
  /** Pestañas */
  readonly tabs = input.required<MfTab[]>();
  /** Índice seleccionado */
  readonly selectedIndex = input(0);
  /** Variante visual */
  readonly variant = input<MfTabsVariant>('default');

  readonly mfSelectedIndexChange = output<number>();

  readonly hostClasses = computed(() => {
    return ['mf-tabs', `mf-tabs--${this.variant()}`].join(' ');
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatInputModule } from '@angular/material/input';
import { MatFormFieldModule } from '@angular/material/form-field';

export type MfTextareaSize = 'sm' | 'md' | 'lg';
export type MfTextareaResize = 'none' | 'vertical' | 'horizontal' | 'both';

/**
 * Textarea de la librería mf-components.
 * Envuelve Angular Material `matInput` con textarea y expone una API uniforme
 * con look and feel de marca.
 */
@Component({
  selector: 'mf-textarea',
  imports: [MatInputModule, MatFormFieldModule],
  template: `
    <mat-form-field [appearance]="'outline'" [class]="hostClasses()">
      @if (label()) {
        <mat-label>{{ label() }}</mat-label>
      }
      <textarea
        matInput
        [placeholder]="placeholder()"
        [disabled]="disabled()"
        [readonly]="readonly()"
        [rows]="rows()"
        [attr.maxlength]="maxLength() ?? null"
        [value]="value()"
        (input)="onInput($event)"
        (blur)="mfBlur.emit()"
      ></textarea>
      @if (hint()) {
        <mat-hint>{{ hint() }}</mat-hint>
      }
      @if (maxLength()) {
        <mat-hint align="end">{{ currentLength() }} / {{ maxLength() }}</mat-hint>
      }
    </mat-form-field>
  `,
  styleUrl: './mf-textarea.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfTextareaComponent {
  /** Etiqueta */
  readonly label = input<string | undefined>(undefined);
  /** Placeholder */
  readonly placeholder = input<string>('');
  /** Valor */
  readonly value = input<string>('');
  /** Filas visibles */
  readonly rows = input(4);
  /** Tamaño */
  readonly size = input<MfTextareaSize>('md');
  /** Máximo de caracteres */
  readonly maxLength = input<number | undefined>(undefined);
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Solo lectura */
  readonly readonly = input(false);
  /** Texto de ayuda */
  readonly hint = input<string | undefined>(undefined);
  /** Resize */
  readonly resize = input<MfTextareaResize>('vertical');

  readonly mfInput = output<string>();
  readonly mfBlur = output<void>();

  readonly currentLength = computed(() => this.value().length);

  readonly hostClasses = computed(() => {
    return ['mf-textarea', `mf-textarea--${this.size()}`, `mf-textarea--resize-${this.resize()}`].join(' ');
  });

  onInput(event: Event): void {
    const value = (event.target as HTMLTextAreaElement).value;
    this.mfInput.emit(value);
  }
}

